alter type public.message_channel add value if not exists 'whatsapp';
create table public.message_templates (id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,name text not null,channel public.message_channel not null,subject text,body text not null,created_by uuid references auth.users(id),created_at timestamptz not null default now(),unique(organization_id,name));
create table public.message_audiences (id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,name text not null,filters jsonb not null default '{}',created_at timestamptz not null default now(),unique(organization_id,name));
create table public.message_delivery_attempts (id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,message_recipient_id uuid not null references public.message_recipients(id) on delete cascade,provider text,attempted_at timestamptz not null default now(),response_code text,response_body text,status public.message_status not null);
create table public.communication_preferences (organization_id uuid not null references public.organizations(id) on delete cascade,member_profile_id uuid not null references public.member_profiles(id) on delete cascade,allow_email boolean not null default true,allow_sms boolean not null default true,allow_whatsapp boolean not null default true,updated_at timestamptz not null default now(),primary key(organization_id,member_profile_id));
alter table public.message_templates enable row level security;alter table public.message_audiences enable row level security;alter table public.message_delivery_attempts enable row level security;alter table public.communication_preferences enable row level security;
create policy "members read templates" on public.message_templates for select using(public.is_organization_member(organization_id));create policy "managers write templates" on public.message_templates for all using(public.can_manage_organization(organization_id)) with check(public.can_manage_organization(organization_id));
create policy "members read audiences" on public.message_audiences for select using(public.is_organization_member(organization_id));create policy "managers write audiences" on public.message_audiences for all using(public.can_manage_organization(organization_id)) with check(public.can_manage_organization(organization_id));
create policy "managers read delivery attempts" on public.message_delivery_attempts for select using(public.can_manage_organization(organization_id));
create policy "members read preferences" on public.communication_preferences for select using(public.is_organization_member(organization_id));create policy "managers write preferences" on public.communication_preferences for all using(public.can_manage_organization(organization_id)) with check(public.can_manage_organization(organization_id));
